const wf = $json.workflow || {};
const err = $json.error || {};
const datum = new Date().toLocaleString('de-DE', { timeZone: 'Europe/Berlin' });

const subject = '[PSA-Backup] Fehler beim NocoDB → MySQL Backup';
const html = '<h2 style="color:#ef4444">Backup fehlgeschlagen</h2>'
  + '<p>Der automatische PSA-Backup-Workflow ist fehlgeschlagen.</p>'
  + '<table style="border-collapse:collapse;font-size:14px">'
  + '<tr><td style="padding:4px 12px 4px 0;font-weight:600">Zeitpunkt:</td><td>' + datum + '</td></tr>'
  + '<tr><td style="padding:4px 12px 4px 0;font-weight:600">Workflow:</td><td>' + (wf.name || 'PSA: NocoDB → MySQL Backup') + '</td></tr>'
  + '<tr><td style="padding:4px 12px 4px 0;font-weight:600">Fehler:</td><td>' + (err.message || 'Unbekannter Fehler') + '</td></tr>'
  + '<tr><td style="padding:4px 12px 4px 0;font-weight:600">Node:</td><td>' + (err.node ? err.node.name : '-') + '</td></tr>'
  + '</table>'
  + '<p style="margin-top:16px">Bitte n8n öffnen und den Fehler prüfen.</p>';

return [{ json: { subject, html } }];
